@page "/catalog"
@using sv_8cda67b7408141dc818e84f86f12a7a5.Components.Catalog
@rendermode InteractiveServer
@inject IProductService ProductService

<PageTitle>Product Catalog</PageTitle>

<h3 class="mb-3">Product Catalog</h3>

<div class="row">
    @* Sidebar *@
    <div class="col-md-3">
        <CatalogSidebar Categories="categories"
                        OnFiltersApplied="HandleFiltersApplied" />
    </div>

    @* Main content *@
    <div class="col-md-9">
        @if (error is not null)
        {
            <div class="alert alert-danger" role="alert">
                <strong>Error:</strong> @error
            </div>
        }
        else if (loading)
        {
            <div class="d-flex justify-content-center py-5">
                <div class="spinner-border text-primary" role="status">
                    <span class="visually-hidden">Loading...</span>
                </div>
            </div>
        }
        else if (result is not null && result.Items.Count > 0)
        {
            <CatalogToolbar SortBy="@sortBy"
                            Page="currentPage"
                            PageSize="pageSize"
                            TotalCount="result.TotalCount"
                            OnSortChanged="HandleSortChanged" />

            <ProductGrid Products="result.Items"
                         OnProductSelected="HandleProductSelected"
                         OnAddToCart="HandleAddToCart" />

            <CatalogPagination Page="currentPage"
                               TotalPages="TotalPages"
                               OnPageChanged="HandlePageChanged" />
        }
        else
        {
            <div class="text-center py-5 text-muted">
                <h5>No products found</h5>
                <p>Try adjusting your filters.</p>
            </div>
        }
    </div>
</div>

@code {
    private List<string> categories = [];
    private PagedResult<Product>? result;
    private ProductFilter currentFilter = new(null, null, null, false);
    private string sortBy = "price_asc";
    private int currentPage = 1;
    private const int pageSize = 12;
    private bool loading = true;
    private string? error;

    private int TotalPages => result is null || result.TotalCount == 0
        ? 1
        : (int)Math.Ceiling((double)result.TotalCount / pageSize);

    protected override async Task OnInitializedAsync()
    {
        try
        {
            var categoriesTask = ProductService.GetCategoriesAsync();
            var searchTask = ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);
            await Task.WhenAll(categoriesTask, searchTask);
            categories = categoriesTask.Result;
            result = searchTask.Result;
        }
        catch (Exception ex)
        {
            error = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private async Task SearchAsync()
    {
        loading = true;
        error = null;
        StateHasChanged();

        try
        {
            result = await ProductService.SearchAsync(currentFilter, sortBy, currentPage, pageSize);
        }
        catch (Exception ex)
        {
            error = ex.Message;
        }
        finally
        {
            loading = false;
        }
    }

    private async Task HandleFiltersApplied(ProductFilter filter)
    {
        currentFilter = filter;
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandleSortChanged(string? newSort)
    {
        sortBy = newSort ?? "price_asc";
        currentPage = 1;
        await SearchAsync();
    }

    private async Task HandlePageChanged(int page)
    {
        currentPage = page;
        await SearchAsync();
    }

    [Parameter]
    public EventCallback<Product> OnProductSelected { get; set; }

    private async Task HandleProductSelected(Product product)
    {
        await OnProductSelected.InvokeAsync(product);
    }

    private Task HandleAddToCart(Product product)
    {
        // Placeholder for cart integration
        return Task.CompletedTask;
    }
}

